function deregister_account_association end

function deregister_account_association(
    AccountAssociationId, ManagedThingId; aws_config::AbstractAWSConfig=current_aws_config()
)
    return iot_managed_integrations(
        "PUT",
        "/managed-thing-associations/deregister",
        Dict{String,Any}(
            "AccountAssociationId" => AccountAssociationId,
            "ManagedThingId" => ManagedThingId,
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function deregister_account_association(
    AccountAssociationId,
    ManagedThingId,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return iot_managed_integrations(
        "PUT",
        "/managed-thing-associations/deregister",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "AccountAssociationId" => AccountAssociationId,
                    "ManagedThingId" => ManagedThingId,
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

