"""
    send_connector_event(connector_id, operation)
    send_connector_event(connector_id, operation, params::Dict{String,<:Any})

Relays third-party device events for a connector such as a new device or a device state
change event.

# Arguments

- `connector_id`: The id of the connector between the third-party cloud provider and IoT
  managed integrations.

- `operation`: The Open Connectivity Foundation (OCF) operation requested to be performed on
  the managed thing.

  !!! note
      The field op can have a value of "I" or "U". The field "cn" will contain the
      capability types.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"ConnectorDeviceId"`: The third-party device id as defined by the connector. This device
  id must not contain personal identifiable information (PII).

  !!! note
      This parameter is used for cloud-to-cloud devices only.

- `"DeviceDiscoveryId"`: The id for the device discovery job.

- `"Devices"`: The list of devices.

- `"MatterEndpoint"`: The device endpoint.

- `"Message"`: The device state change event payload.

  This parameter will include the following three fields:

  - `uri`: `schema auc://&lt;PARTNER-DEVICE-ID&gt;/ResourcePath` (The `Resourcepath`
    corresponds to an OCF resource.)
  - `op`: For device state changes, this field must populate as `n+d`.
  - `cn`: The content depends on the OCF resource referenced in `ResourcePath`.

- `"OperationVersion"`: The Open Connectivity Foundation (OCF) security specification
  version for the operation being requested on the managed thing. For more information, see [OCF Security Specification](https://openconnectivity.org/specs/OCF_Security_Specification_v1.0.0.pdf).

- `"StatusCode"`: The status code of the Open Connectivity Foundation (OCF) operation being
  performed on the managed thing.

- `"TraceId"`: The trace request identifier. This is generated by IoT managed integrations
  and can be used to trace this command and its related operations in CloudWatch.

- `"UserId"`: The id of the third-party cloud provider.
"""
function send_connector_event end

function send_connector_event(
    ConnectorId, Operation; aws_config::AbstractAWSConfig=current_aws_config()
)
    return iot_managed_integrations(
        "POST",
        "/connector-event/$(ConnectorId)",
        Dict{String,Any}("Operation" => Operation);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function send_connector_event(
    ConnectorId,
    Operation,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return iot_managed_integrations(
        "POST",
        "/connector-event/$(ConnectorId)",
        Dict{String,Any}(
            mergewith(_merge, Dict{String,Any}("Operation" => Operation), params)
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

